/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return 0;
    }

    // dp_up[i]: maximum score of a strictly alternating subsequence ending at index i,
    // where the last transition was increasing (i.e., nums[j] < nums[i] for the previous element j).
    // The sequence ends with <.
    const dp_up = new Array(n).fill(nums[0]);

    // dp_down[i]: maximum score of a strictly alternating subsequence ending at index i,
    // where the last transition was decreasing (i.e., nums[j] > nums[i] for the previous element j).
    // The sequence ends with >.
    const dp_down = new Array(n).fill(nums[0]);

    let maxScore = nums[0];

    for (let i = 1; i < n; i++) {
        // Base case: a sequence of length 1 ending at i always has score nums[i]
        dp_up[i] = nums[i];
        dp_down[i] = nums[i];

        for (let j = 0; j < i; j++) {
            if (i - j >= k) {
                // Try to extend a sequence ending at j with nums[i]

                // 1. Current element nums[i] makes the sequence end with '<' (i.e., previous was '>').
                // Previous sequence must have ended with a decrease (>), so we use dp_down[j].
                if (nums[j] < nums[i]) {
                    // If dp_down[j] is the score ending in ..., > nums[j], then we form ..., > nums[j] < nums[i]
                    // The new score is dp_down[j] + nums[i].
                    // We take the max because dp_up[i] might already be better from a shorter sequence ending at i.
                    dp_up[i] = Math.max(dp_up[i], dp_down[j] + nums[i]);
                }

                // 2. Current element nums[i] makes the sequence end with '>' (i.e., previous was '<').
                // Previous sequence must have ended with an increase (<), so we use dp_up[j].
                if (nums[j] > nums[i]) {
                    // If dp_up[j] is the score ending in ..., < nums[j], then we form ..., < nums[j] > nums[i]
                    // The new score is dp_up[j] + nums[i].
                    dp_down[i] = Math.max(dp_down[i], dp_up[j] + nums[i]);
                }
            }
        }

        maxScore = Math.max(maxScore, dp_up[i], dp_down[i]);
    }

    return maxScore;
}

