                    // If dp_down[j] is the score ending in ..., > nums[j], then we form ..., > nums[j] < nums[i]
                    // The new score is dp_down[j] + nums[i].
                    // We take the max because dp_up[i] might already be better from a shorter sequence ending at i.
                    dp_up[i] = Math.max(dp_up[i], dp_down[j] + nums[i]);
                }

                // 2. Current element nums[i] makes the sequence end with '>' (i.e., previous was '<').
                // Previous sequence must have ended with an increase (<), so we use dp_up[j].
                if (nums[j] > nums[i]) {
                    // If dp_up[j] is the score ending in ..., < nums[j], then we form ..., < nums[j] > nums[i]
                    // The new score is dp_up[j] + nums[i].
                    dp_down[i] = Math.max(dp_down[i], dp_up[j] + nums[i]);
                }
            }
        }

        maxScore = Math.max(maxScore, dp_up[i], dp_down[i]);
    }

    return maxScore;
}
